#include<bits/stdc++.h>
using namespace std;
int main() {
	int n, a[100001] = {0},ans=0;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	sort(a + 1, a + n + 1);
	while (n > 3) {
		ans += min(a[1] * 2 + a[n] + a[n - 1], a[1] + a[2] * 2 + a[n]); 
		n -= 2; 
	}
	if (n == 2) ans += a[2]; 
	if (n == 3) ans += a[1] + a[2] + a[3];
    cout<<ans;
	return 0;
}
